#include <bits/stdc++.h>
using namespace std;
const int N=10005,M=100005;
int n,m,a[N];
int tot,tot2,dfn[N],low[N],cnt2;
vector<int> g[N];
stack<int> st;
int vis[N],cnt;
void tarjan(int u,int f)
{
	low[u]=dfn[u]=++cnt;
	st.push(u);
	vis[u]=1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==f) continue;
		if(!dfn[v])
		{
			tarjan(v,u);
			low[u]=min(low[u],low[v]);
		}
		else if(vis[v])
		{
			low[u]=min(low[u],dfn[v]);
		}
	}
	if(low[u]==dfn[u])
	{
		cnt2++;
		int v;
		while(v=st.top())
		{
			vis[v]=0;
			st.pop();
			if(v==u) break;
		}
	}
}
int main()
{
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
	}
	for(int i=1;i<=n;i++)
	{
		if(!dfn[i]) tarjan(i,0);
	}
	cout<<(cnt2+1)/2;
	return 0;
}
